import './ProductCard.css';import PropTypes from 'prop-types';export default function ProductCard({productName,price}){return(<div className='card shadow p-3 product-card'><div className='card-body'><h3>{productName}</h3><h4 className='text-success'>₹ {price}</h4><button className='btn btn-primary mt-3'>Buy Now</button></div></div>)} ProductCard.propTypes={productName:PropTypes.string.isRequired,price:PropTypes.number.isRequired};